import { motion } from "framer-motion";
import { adminDashboardDesign } from "../../design/adminDashboardDesign";

const AdminDashboard = () => {
  const adminInfo = JSON.parse(localStorage.getItem("adminInfo"));

  return (
    <motion.div
      {...adminDashboardDesign.animation.container}
      className={`${adminDashboardDesign.colors.background} ${adminDashboardDesign.layout.container}`}
    >
      {/* Sidebar */}
      <div
        className={`${adminDashboardDesign.colors.sidebar} ${adminDashboardDesign.layout.sidebar}`}
      >
        <h2 className="text-2xl font-bold text-indigo-400">
          Admin Panel
        </h2>

        <nav className="flex flex-col space-y-3">
          <button className="text-left hover:text-indigo-400 transition">
            Dashboard
          </button>
          <button className="text-left hover:text-indigo-400 transition">
            Products
          </button>
          <button className="text-left hover:text-indigo-400 transition">
            Orders
          </button>
          <button className="text-left hover:text-indigo-400 transition">
            Users
          </button>
        </nav>
      </div>

      {/* Main Content */}
      <div className={adminDashboardDesign.layout.content}>
        <h1 className="text-3xl font-bold mb-2">
          Welcome, {adminInfo?.name}
        </h1>
        <p className={`${adminDashboardDesign.colors.textSecondary} mb-8`}>
          This is your Admin Dashboard overview 🚀
        </p>

        {/* Cards */}
        <div className={adminDashboardDesign.layout.grid}>
          {["Total Sales", "Total Orders", "Total Products", "Total Users"].map(
            (item, index) => (
              <motion.div
                key={index}
                {...adminDashboardDesign.animation.card}
                className={`${adminDashboardDesign.colors.card} ${adminDashboardDesign.layout.card}`}
              >
                <h3 className="text-lg font-semibold mb-2">{item}</h3>
                <p className="text-2xl font-bold text-indigo-400">
                  0{index + 1}00
                </p>
              </motion.div>
            )
          )}
        </div>
      </div>
    </motion.div>
  );
};

export default AdminDashboard;
